import {useEffect, useState} from "react";
import KitsInputText from "../../../../form/inputs/InputText";
import {type EditorEl} from "../Editor";
import type {Timeout} from "@lmb-it/kitsconcerto-types";

const timeoutPeriod = 500;

const PhoneEditor: EditorEl<{
  no?:null
}> = (options) => {
  const [value, setValue] = useState<string>("");
  const [timeoutId, setTimeoutId] = useState<Timeout | null>(null);

  useEffect(() => {
    if (options && "value" in options) {
      setValue(options.value != null ? String(options.value) : "");
    }
  }, [options]);

  const onInputChange = (e: any) => {
    const newTerm = e.target?.value ?? e ?? '';
    setValue(newTerm);

    if (timeoutId) clearTimeout(timeoutId);

    const newTimeoutId = setTimeout(() => {
      options.editorCallback && options.editorCallback(newTerm);
    }, timeoutPeriod);

    setTimeoutId(newTimeoutId);
  };

  return (
    <KitsInputText
      attached
      id={"editor-phone-number"}
      value={value}
      onChange={onInputChange}
      onKeyDown={(e: any) => {
        if (e.key === "Enter") {
          if (timeoutId) clearTimeout(timeoutId);
          options.editorCallback && options.editorCallback(value);
        }
      }}
      keyFilter={/[\d\s\-+()]/}
      inputSize="sm"
      localProps={{ style: { width: '100%' } }}
    />
  );
};

export default PhoneEditor;
